import{_ as a,o as e,c as i,e as l}from"./app-52052bff.js";const h="/assets/image-33ac98c8.png",r={},d=l('<h2 id="软件测试" tabindex="-1"><a class="header-anchor" href="#软件测试" aria-hidden="true">#</a> 软件测试</h2><h3 id="定义" tabindex="-1"><a class="header-anchor" href="#定义" aria-hidden="true">#</a> 定义</h3><p>软件 = 文档 + 程序 + 数据</p><p>软件测试就是一个过程或者一系列过程，用来确保程序完成了其应该完成的功能，并且不会执行不该执行的操作。软件应该是可以预测且稳定的，不会给用户带来意外的情况。</p><h3 id="对象" tabindex="-1"><a class="header-anchor" href="#对象" aria-hidden="true">#</a> 对象</h3><p>软件测试 != 程序测试，软件测试贯穿于软件定义和开发的整个期间。需求分析，概要设计，详细设计以及程序编码等各个阶段所得到的文档（需求规格说明，概要设计规格说明，详细设计规格说明以及源程序）都是软件测试的对象</p><h2 id="软件测试的分类" tabindex="-1"><a class="header-anchor" href="#软件测试的分类" aria-hidden="true">#</a> 软件测试的分类</h2><ul><li>按开发阶段分类：单元测试，集成测试，系统测试，验收测试</li><li>按测试组织分类：开发方测试，用户测试，第三方测试</li><li>按测试技术分类：白盒测试，黑盒测试，灰盒测试</li></ul><h2 id="软件测试流程" tabindex="-1"><a class="header-anchor" href="#软件测试流程" aria-hidden="true">#</a> 软件测试流程</h2><ol><li>根据需求设计测试计划</li><li>设计并编写测试用例</li><li>执行测试用例，提交缺陷报告</li><li>提交测试总结报告</li></ol><h2 id="测试用例" tabindex="-1"><a class="header-anchor" href="#测试用例" aria-hidden="true">#</a> 测试用例</h2><p>测试用例是为某个特殊目标而编制的一组测试输入，执行条件以及预期结果，用于核实是否满足某个特定软件需求</p><p>好处:</p><ul><li>理清思路，避免遗漏</li><li>跟踪测试进展</li><li>历史参考</li><li>重复使用</li></ul><h3 id="测试用例的编写" tabindex="-1"><a class="header-anchor" href="#测试用例的编写" aria-hidden="true">#</a> 测试用例的编写</h3><ul><li>等价类划分：将输入集合划分为两个子集合：有效等价类和无效等价类。有效等价类就是有效的输入，无效等价类就是无效的输入</li><li>边界值划分：对等价类的补充，因为有很多错误都是出现在输入输出的边界上。找出等价类的边界点，对边界数据进行测试</li><li>因果图：根据输入条件的各种组合条件，生成判定表</li><li>错误推测法：基于经验和直觉推测出系统可能存在的错误，从而有针对性的设计测试用例的方法</li></ul><p>例子：假如有一个输入框要求输入1-10000个数。</p><p>等价类划分：有效等价类和无效等价类，输入框要求输入1-10000的数</p><ul><li>有效等价类：可以输入1-10000之间的数来验证，如：2、5、99、8495......</li><li>无效等价类：可以输入1-10000之外的任意字符验证，如：20000、字母、下划线、特殊符号、空格、回车.....</li></ul><p>边界值划分：0、-1、-2、1000、10001.....</p><h3 id="测试用例的格式" tabindex="-1"><a class="header-anchor" href="#测试用例的格式" aria-hidden="true">#</a> 测试用例的格式</h3><p>一个测试用例应该包括：编号，标题，测试场景，测试步骤，预期结果，其他（优先级，测试阶段等）</p><p><img src="'+h+'" alt="alt text"></p><h2 id="bug的处理" tabindex="-1"><a class="header-anchor" href="#bug的处理" aria-hidden="true">#</a> Bug的处理</h2>',24),t=[d];function n(s,c){return e(),i("div",null,t)}const p=a(r,[["render",n],["__file","test.html.vue"]]);export{p as default};
